import React from 'react';
import './Comparison.css';

const ROWS = [
  {
    feature: 'Easy to complex cases',
    whistle: 'Yes, mild to complex',
    others: 'No, only mild to moderate',
  },
  {
    feature: 'Clear-cut Pricing',
    whistle: true,
    others: false,
  },
  {
    feature: 'Aligner Change',
    whistle: 'Every 10 days',
    others: 'Every 2 weeks',
  },
  {
    feature: 'Clinical Partnership',
    whistle: true,
    others: false,
  },
  {
    feature: 'Movement Between Cities',
    whistle: true,
    others: false,
  },
  {
    feature: 'Complimentary Teeth Scaling',
    whistle: true,
    others: false,
  },
];

function Cell({ value, purple }) {
  if (value === true)
    return <span className="icon-wrap icon-yes">✓</span>;
  if (value === false)
    return <span className="icon-wrap icon-no">✗</span>;
  return (
    <span className={purple ? 'tag-purple' : 'tag-grey'}>{value}</span>
  );
}

export default function Comparison() {
  return (
    <section className="comp-section">
      <div className="comp-inner">
        <h2 className="comp-title">What sets Whistle apart?</h2>
        <div className="comp-table-wrap">
          <table className="comp-table">
            <thead>
              <tr>
                <th className="col-feature">Features</th>
                <th>
                  <span className="whistle-badge">
                    whistle
                    <span className="sub">AND SMILE</span>
                  </span>
                </th>
                <th>Other Brands</th>
              </tr>
            </thead>
            <tbody>
              {ROWS.map((row, i) => (
                <tr key={i}>
                  <td className="feature-cell">{row.feature}</td>
                  <td><Cell value={row.whistle} purple /></td>
                  <td><Cell value={row.others} /></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </section>
  );
}
